    if (nodeIdNum < 1 || nodeIdNum > 99) throw new Error('Node id out of range: ' + nodeStr);
    const nodePadded = String(nodeIdNum).padStart(2, '0');
    return { topic: 'pylon/' + nodePadded + '/control', payload: { cmd: 'attack', type: attackType, duration: durationSec } };
  });
  const mode = (mqttMsgs.length > 1) ? 'botnet' : 'local';
  const summary = { payload: { event: 'attack_dispatched', mode, attack_type: attackType, duration_s: durationSec, target_nodes: deduped.join(',') } };
  node.status({ fill: 'green', shape: 'dot', text: attackType + ' -> ' + deduped.join(',') });
  return [mqttMsgs, summary];
} catch (err) {
  node.status({ fill: 'red', shape: 'ring', text: 'dispatch error' });
  node.warn('[ATTACK-DISPATCH] ' + err.message);
  return [null, { payload: { event: 'attack_dispatch_error', error: err.message, input: msg.payload } }];
}
